684	/// The per-cell fit **budgets** of one record group (all premises together, or
685	/// all conclusions together), from the cells' flat texts. Two probe-derived
686	/// layers (BEHAVIOR.md §3f, rounds 9–10; every parameter pinned by live probe
687	/// batteries — QUERIES.log Sessions 9–10):
688	///
689	/// **Trigger** (which cells wrap). Each cell occupies
690	/// `C_j = flat_j + Σ_{top-level tuple/union args}(elems + 1)` columns of the
691	/// row (the round-10 size law: X-flip boundaries at n = 2,3,4,6 tuples and
692	/// 3,5,8 unions are each exact to the column); cell *i*'s trigger budget is
693	/// `max(87 + bonus_i − Σ_{j≠i} C_j, 20)` in a multi-cell row, where
694	/// `bonus_i` = the largest `⌊elems/2⌋ + 2` over its tuple/union args (4 for
695	/// an arg with ≥ 9 elements — the r8 16/20-element rows cap it), and it
696	/// wraps iff its flat width exceeds that budget. A lone cell's budget is
697	/// exactly 87. There is NO single-quoted-atom, multi-quote, or
698	/// function-node correction (round-10 batteries A–C: every such sib flips
699	/// exactly at the plain-flat crossing). The only systematic residual is the
700	/// `[45-argfact partner, budget+1]` relief (9/731 probe cells, all one
701	/// pattern: beside a 45-flat argfact partner a cell at exactly budget+1
702	/// stays flat; beside 46 or in triples it does not) — the known ±1
703	/// coupled-`fits` flip, not modelable in closed form.
704	///
705	/// **Fill** (the ribbon a wrapping cell is laid out at):
706	/// `round(87·N_i / (N_i + Σ_{j≠i} w_j·flat_j))`, half-up, clamped to
707	/// `[20, flat_i − 1]`, where the numerator `N_i = flat_i + Σ_{union
708	/// args}(elems + 1) + nfunc_i` is the cell's *internal* width (unions carry
709	/// their spaced internal separators, function applications ~1 column each —
710	/// pinned by the UD/UG/DN/FE squeezed fills), and `w_j = 5/6` for
711	/// single-quoted-atom siblings of a tuple-fact receiver (round-9 Q/I series:
712	/// the [Big 87, atom s] fill follows 87²/(87 + 5s/6) across s = 12…120),
713	/// else 1 (round-10 argfact receivers track the plain share). Tuple args do
714	/// NOT enter the numerator (the live `Wide` record byte-pins the tuple
715	/// receiver at the display-flat share). A fitting cell keeps
716	/// `max(trigger, flat)` so it renders flat.
717	pub fn group_widths(cells: &[String]) -> Vec<usize> {
718	    group_widths_with(cells, &[])
719	}
720	
721	/// [`group_widths`] with caller-supplied per-cell width inputs. `overrides` is
722	/// either empty (all cells use display-text estimates — byte-identical to
723	/// [`group_widths`]) or one `Option<CellWidths>` per cell; each present field
724	/// of a present entry replaces the corresponding display-text estimate
725	/// (occupancy `C`, budget bonus, fill numerator) for that cell, and every
726	/// absent field falls back per-field. The display flat width itself always
727	/// comes from the text (it *is* the rendered content).
728	pub fn group_widths_with(cells: &[String], overrides: &[Option<CellWidths>]) -> Vec<usize> {
729	    let shapes: Vec<CellShape> = cells.iter().map(|t| cell_shape(t)).collect();
730	    let n = shapes.len();
731	    let full = FILL_WIDTH as i64; // 87
732	    let ov = |i: usize| -> Option<&CellWidths> { overrides.get(i).and_then(|o| o.as_ref()) };
733	    let cs: Vec<i64> = shapes
734	        .iter()
735	        .enumerate()
736	        .map(|(i, s)| {
737	            ov(i)
738	                .and_then(|w| w.occupancy)
739	                .unwrap_or(s.flat as i64 + s.tup_sur + s.uni_sur)
740	        })
741	        .collect();
742	    let ctot: i64 = cs.iter().sum();
743	    let mut out = Vec::with_capacity(n);
744	    for (i, sh) in shapes.iter().enumerate() {
745	        let flat = sh.flat as i64;
746	        if n == 1 {
747	            out.push(full as usize);
748	            continue;
749	        }
750	        let bonus = ov(i).and_then(|w| w.bonus).unwrap_or(sh.bmax);
751	        let b_trig = (full + bonus - (ctot - cs[i])).max(MIN_CELL_BUDGET as i64);
752	        if flat <= b_trig {
753	            // fits: any budget ≥ flat renders the cell flat
754	            out.push(b_trig.max(flat) as usize);
755	            continue;
756	        }
757	        // wraps: proportional fill share; the numerator is the cell's internal
758	        // width (union separators + function nodes), siblings at their
759	        // occupancy C with single-quoted atoms discounted 5/6 for a
760	        // tuple-fact receiver
761	        let num = ov(i)
762	            .and_then(|w| w.fill_width)
763	            .unwrap_or(flat + sh.uni_sur + sh.nfunc) as f64;
764	        let mut t = num;
765	        for j in 0..n {
766	            if j != i {
767	                let w = if shapes[j].sqa && sh.tup_sur > 0 { 5.0 / 6.0 } else { 1.0 };
768	                t += w * cs[j] as f64;
769	            }
770	        }
771	        let mut b = ((full as f64) * num / t + 0.5).floor() as i64;
772	        b = b.max(MIN_CELL_BUDGET as i64).min((flat - 1).max(MIN_CELL_BUDGET as i64));
773	        out.push(b as usize);
774	    }
775	    out
776	}
777	
778	/// Wrap every cell of one record group, sharing the row via
779	/// [`group_widths_with`] and laying each cell out at its budget with the
780	/// faithful engine.
781	fn group_cells(flat_cells: &[String], ports: &[String], widths: &[Option<CellWidths>]) -> Vec<Cell> {
782	    let fills = group_widths_with(flat_cells, widths);
783	    flat_cells
784	        .iter()
785	        .zip(ports)
786	        .zip(fills)
787	        .map(|((text, p), w)| Cell::new(p.clone(), wrap_cell_dot(text, w as isize)))
788	        .collect()
789	}
