//! Open-side occupancy-adapter census.
//!
//! For every record in the corpus: parse the legend node into a NAME->EXPANSION
//! map, dewrap each prem/concl cell to its (post-abbreviation) display flat,
//! recover the UN-ABBREVIATED internal rendering by fixpoint legend expansion,
//! compute per-cell `CellWidths` (occupancy / bonus / fill numerator) on that
//! internal text, and drive the clean crate's `group_widths_with` +
//! `wrap_cell_dot` with those overrides. Compares produced bytes to the actual
//! cell bytes, for three modes: baseline (no override), occupancy-only, and
//! occupancy+bonus+fill. Reports overall + wrap-sensitive counts and residual
//! families.

use graph_clean::doclayout::wrap_cell_dot;
use graph_clean::generate::{group_widths_with, CellWidths};

// ---------- record-label parsing (mirrors tests/census.rs) ----------

fn split_top_pipes(s: &str) -> Vec<String> {
    let mut out = Vec::new();
    let mut cur = String::new();
    let mut depth = 0i32;
    let bytes: Vec<char> = s.chars().collect();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i];
        if c == '\\' && i + 1 < bytes.len() {
            cur.push(c);
            cur.push(bytes[i + 1]);
            i += 2;
            continue;
        }
        match c {
            '{' => { depth += 1; cur.push(c); }
            '}' => { depth -= 1; cur.push(c); }
            '|' if depth == 0 => out.push(std::mem::take(&mut cur)),
            _ => cur.push(c),
        }
        i += 1;
    }
    out.push(cur);
    out
}

fn strip_braces(s: &str) -> &str {
    let s = s.trim();
    let s = s.strip_prefix('{').unwrap_or(s);
    s.strip_suffix('}').unwrap_or(s)
}

fn unescape(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let cs: Vec<char> = s.chars().collect();
    let mut i = 0;
    while i < cs.len() {
        if cs[i] == '\\' && i + 1 < cs.len() && matches!(cs[i + 1], '<' | '>' | '{' | '}' | '|') {
            out.push(cs[i + 1]);
            i += 2;
        } else {
            out.push(cs[i]);
            i += 1;
        }
    }
    out
}

fn strip_port(cell: &str) -> &str {
    let c = cell.trim_start();
    if let Some(rest) = c.strip_prefix('<') {
        if let Some(gt) = rest.find('>') {
            let after = &rest[gt + 1..];
            return after.strip_prefix(' ').unwrap_or(after);
        }
    }
    c
}

fn dewrap(cell: &str) -> String {
    if !cell.contains("\\l") {
        return unescape(cell);
    }
    let raw_lines: Vec<&str> = cell.split("\\l").collect();
    let mut lines: Vec<(bool, String)> = Vec::new();
    for (i, l) in raw_lines.iter().enumerate() {
        if i + 1 == raw_lines.len() && l.is_empty() {
            break;
        }
        let mut rest = *l;
        let mut indented = false;
        while let Some(r) = rest.strip_prefix("&nbsp;") {
            rest = r;
            indented = true;
        }
        lines.push((indented, unescape(rest)));
    }
    if lines.is_empty() {
        return String::new();
    }
    let mut flat = lines[0].1.clone();
    for (indented, li) in &lines[1..] {
        if flat.ends_with(", ") {
            flat.push_str(li);
        } else if flat.ends_with(',') {
            flat.push(' ');
            flat.push_str(li);
        } else if li == ")" && !indented {
            flat.push_str(" )");
        } else {
            flat.push_str(li);
        }
    }
    flat
}

struct Rec {
    // per group cell (raw wrapped bytes, display flat)
    premises: Vec<(String, String)>,
    conclusions: Vec<(String, String)>,
}

fn parse_record(label: &str) -> Option<Rec> {
    let inner = strip_braces(label);
    let groups = split_top_pipes(inner);
    let mut parsed: Vec<Vec<(String, String)>> = Vec::new();
    for g in &groups {
        let gi = strip_braces(g);
        let cells = split_top_pipes(gi);
        let v: Vec<(String, String)> = cells
            .iter()
            .map(|c| {
                let raw = strip_port(c).to_string();
                let flat = dewrap(&raw);
                (raw, flat)
            })
            .collect();
        parsed.push(v);
    }
    let mut info_idx = None;
    for (i, g) in parsed.iter().enumerate() {
        if g.first().map(|c| c.1.starts_with('#')).unwrap_or(false) {
            info_idx = Some(i);
            break;
        }
    }
    let info_idx = info_idx?;
    let premises: Vec<(String, String)> = parsed[..info_idx].iter().flatten().cloned().collect();
    let conclusions: Vec<(String, String)> = parsed[info_idx + 1..].iter().flatten().cloned().collect();
    Some(Rec { premises, conclusions })
}

fn each_record_label(dot: &str) -> Vec<String> {
    let mut out = Vec::new();
    for line in dot.lines() {
        if !line.contains("shape=\"record\"") {
            continue;
        }
        if let Some(start) = line.find("label=\"") {
            let after = &line[start + 7..];
            if let Some(end) = after.find("\",fillcolor=") {
                out.push(after[..end].to_string());
            }
        }
    }
    out
}

// ---------- legend parsing + expansion ----------

fn html_unescape(s: &str) -> String {
    s.replace("&lt;", "<").replace("&gt;", ">").replace("&amp;", "&")
}

/// Parse the legend plain-node rows into (NAME, EXPANSION) pairs.
fn parse_legend(dot: &str) -> Vec<(String, String)> {
    let mut map = Vec::new();
    for line in dot.lines() {
        if !line.contains("shape=\"plain\"") || !line.contains("<TABLE") {
            continue;
        }
        // rows: <FONT COLOR="#000000">NAME</FONT></TD> <TD ...>=</TD> <TD ...>EXP</TD></TR>
        let mut rest = line;
        while let Some(fp) = rest.find("<FONT COLOR=\"#000000\">") {
            let after = &rest[fp + "<FONT COLOR=\"#000000\">".len()..];
            let Some(fe) = after.find("</FONT>") else { break };
            let name = &after[..fe];
            // find the "=" TD then the expansion TD
            let tail = &after[fe..];
            let Some(eq) = tail.find(">=</TD>") else { rest = tail; continue };
            let after_eq = &tail[eq + ">=</TD>".len()..];
            // next <TD ...>EXP</TD>
            let Some(td) = after_eq.find("<TD ALIGN=\"LEFT\" VALIGN=\"TOP\">") else {
                rest = after_eq;
                continue;
            };
            let after_td = &after_eq[td + "<TD ALIGN=\"LEFT\" VALIGN=\"TOP\">".len()..];
            let Some(tde) = after_td.find("</TD>") else { rest = after_td; continue };
            let exp = html_unescape(&after_td[..tde]);
            map.push((name.to_string(), exp));
            rest = &after_td[tde..];
        }
    }
    map
}

fn is_ident_char(c: char) -> bool {
    c.is_ascii_alphanumeric() || c == '_'
}

/// Substitute every legend NAME token in `text` by its expansion, to fixpoint.
/// Names are matched only as whole identifier tokens.
fn expand(text: &str, legend: &[(String, String)]) -> String {
    // legend names sorted by length desc for greedy token match
    let mut cur = text.to_string();
    for _ in 0..64 {
        let mut changed = false;
        for (name, exp) in legend {
            if name.is_empty() {
                continue;
            }
            let mut out = String::with_capacity(cur.len());
            let bytes: Vec<char> = cur.chars().collect();
            let nlen = name.chars().count();
            let nchars: Vec<char> = name.chars().collect();
            let mut i = 0;
            while i < bytes.len() {
                let mut matched = false;
                if i + nlen <= bytes.len() && bytes[i..i + nlen] == nchars[..] {
                    let before_ok = i == 0 || !is_ident_char(bytes[i - 1]);
                    let after_ok = i + nlen >= bytes.len() || !is_ident_char(bytes[i + nlen]);
                    if before_ok && after_ok {
                        out.push_str(exp);
                        i += nlen;
                        matched = true;
                        changed = true;
                    }
                }
                if !matched {
                    out.push(bytes[i]);
                    i += 1;
                }
            }
            cur = out;
        }
        if !changed {
            break;
        }
    }
    cur
}

// ---------- cell shape law (mirrors generate::cell_shape, applied to the
//            UN-abbreviated internal text to produce CellWidths overrides) ----------

fn split_level(s: &str) -> Vec<&str> {
    let b: Vec<(usize, char)> = s.char_indices().collect();
    let mut parts = Vec::new();
    let (mut depth, mut inq, mut start) = (0i32, false, 0usize);
    let mut i = 0;
    while i < b.len() {
        let (pos, c) = b[i];
        if inq {
            if c == '\'' {
                inq = false;
            }
        } else {
            match c {
                '\'' => inq = true,
                '(' | '<' | '[' => depth += 1,
                ')' | '>' | ']' => depth -= 1,
                ',' if depth == 0 && i + 1 < b.len() && b[i + 1].1 == ' ' => {
                    parts.push(&s[start..pos]);
                    start = b[i + 1].0 + 1;
                    i += 1;
                }
                _ => {}
            }
        }
        i += 1;
    }
    parts.push(&s[start..]);
    parts
}

fn union_elems(t: &str) -> i64 {
    if !(t.starts_with('(') && t.ends_with(')')) || t.len() < 2 {
        return 0;
    }
    let inner = &t[1..t.len() - 1];
    let b: Vec<char> = inner.chars().collect();
    let (mut depth, mut inq, mut n) = (0i32, false, 1i64);
    let mut i = 0;
    while i < b.len() {
        let c = b[i];
        if inq {
            if c == '\'' {
                inq = false;
            }
        } else {
            match c {
                '\'' => inq = true,
                '(' | '<' | '[' => depth += 1,
                ')' | '>' | ']' => depth -= 1,
                '+' if depth == 0 && i + 1 < b.len() && b[i + 1] == '+' => {
                    n += 1;
                    i += 1;
                }
                _ => {}
            }
        }
        i += 1;
    }
    if n >= 2 { n } else { 0 }
}

struct Shape {
    flat: i64,
    tup_sur: i64,
    uni_sur: i64,
    bmax: i64,
    nfunc: i64,
}

fn cell_shape(flat: &str) -> Shape {
    let width = flat.chars().count() as i64;
    let (mut tup_sur, mut uni_sur, mut bmax) = (0i64, 0i64, 0i64);
    if let Some(open) = flat.find("( ") {
        if flat.ends_with(" )")
            && open + 2 <= flat.len() - 2
            && !flat[..open].contains(['(', ')', '<', '>', ' ', ','])
        {
            let inner = &flat[open + 2..flat.len() - 2];
            let args = split_level(inner);
            for a in &args {
                let t = a.trim();
                let (elems, is_tuple) = if t.starts_with('<') && t.ends_with('>') {
                    (split_level(&t[1..t.len() - 1]).len() as i64, true)
                } else {
                    (union_elems(t), false)
                };
                if elems >= 2 {
                    if is_tuple {
                        tup_sur += elems + 1;
                    } else {
                        uni_sur += elems + 1;
                    }
                    bmax = bmax.max(if elems <= 8 { elems / 2 + 2 } else { 4 });
                }
            }
        }
    }
    let bch: Vec<char> = flat.chars().collect();
    let mut nfunc = 0i64;
    for i in 1..bch.len() {
        if bch[i] == '('
            && (bch[i - 1].is_alphanumeric() || bch[i - 1] == '_')
            && (i + 1 >= bch.len() || bch[i + 1] != ' ')
        {
            nfunc += 1;
        }
    }
    Shape { flat: width, tup_sur, uni_sur, bmax, nfunc }
}

/// Build the CellWidths override for a cell from its UN-abbreviated internal
/// text `ua`. Returns None if `ua == display` (no abbreviation → exact default,
/// keeps the baseline byte-identical).
fn overrides_for(display: &str, ua: &str, mode: Mode) -> Option<CellWidths> {
    if mode == Mode::Baseline || ua == display {
        return None;
    }
    let s = cell_shape(ua);
    let occupancy = Some(s.flat + s.tup_sur + s.uni_sur);
    match mode {
        Mode::Baseline => None,
        Mode::OccOnly => Some(CellWidths { occupancy, bonus: None, fill_width: None }),
        Mode::Full => Some(CellWidths {
            occupancy,
            bonus: Some(s.bmax),
            fill_width: Some(s.flat + s.uni_sur + s.nfunc),
        }),
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum Mode {
    Baseline,
    OccOnly,
    Full,
}

#[derive(Default)]
struct Tally {
    all: u64,
    all_ok: u64,
    wrap: u64,
    wrap_ok: u64,
    multi_wrap: u64,
    multi_wrap_ok: u64,
    // abbreviated-group wrapping cells (the override's target family)
    abbr_wrap: u64,
    abbr_wrap_ok: u64,
    // residual family counters (on the wrap-sensitive subset)
    false_neg: u64,   // actual wraps, predicted 1-line
    false_pos: u64,   // actual 1-line, predicted wraps
    fill_err: u64,    // both wrap, differ
    // split residuals by whether the miss cell is itself abbreviated
    false_neg_abbr: u64,
    fill_err_abbr: u64,
}

fn run_group(
    cells: &[(String, String)], // (raw, display)
    legend: &[(String, String)],
    mode: Mode,
    is_multi_group: bool,
    t: &mut Tally,
    examples: &mut Vec<(String, String, String, String)>, // family, flat, want, got
) {
    if cells.is_empty() {
        return;
    }
    let display: Vec<String> = cells.iter().map(|c| c.1.clone()).collect();
    let ua: Vec<String> = display.iter().map(|d| expand(d, legend)).collect();
    let group_abbr = display.iter().zip(&ua).any(|(d, u)| d != u);
    let ov: Vec<Option<CellWidths>> = display
        .iter()
        .zip(&ua)
        .map(|(d, u)| overrides_for(d, u, mode))
        .collect();
    let widths = group_widths_with(&display, &ov);
    let multi = cells.len() > 1;
    let _ = is_multi_group;
    for (k, (raw, disp)) in cells.iter().enumerate() {
        let got = wrap_cell_dot(disp, widths[k] as isize);
        let is_wrap = raw.contains("\\l");
        let cell_abbr = display[k] != ua[k];
        let m = &got == raw;
        t.all += 1;
        if m {
            t.all_ok += 1;
        }
        if is_wrap {
            t.wrap += 1;
            if m {
                t.wrap_ok += 1;
            }
            if multi {
                t.multi_wrap += 1;
                if m {
                    t.multi_wrap_ok += 1;
                }
            }
            if group_abbr {
                t.abbr_wrap += 1;
                if m {
                    t.abbr_wrap_ok += 1;
                }
            }
        }
        if !m {
            // classify on the wrap-sensitive dimension
            let got_wraps = got.contains("\\l");
            let fam;
            if is_wrap && !got_wraps {
                t.false_neg += 1;
                if cell_abbr {
                    t.false_neg_abbr += 1;
                }
                fam = "falseNeg";
            } else if !is_wrap && got_wraps {
                t.false_pos += 1;
                fam = "falsePos";
            } else {
                t.fill_err += 1;
                if cell_abbr {
                    t.fill_err_abbr += 1;
                }
                fam = "fillErr";
            }
            if examples.len() < 4000 {
                examples.push((fam.to_string(), disp.clone(), raw.clone(), got.clone()));
            }
        }
    }
}

fn first_diverge(a: &str, b: &str) -> usize {
    a.bytes().zip(b.bytes()).take_while(|(x, y)| x == y).count()
}

fn main() {
    let corpus = std::env::var("GRAPHCLEAN_CORPUS").expect("set GRAPHCLEAN_CORPUS");
    let mut files: Vec<_> = std::fs::read_dir(&corpus)
        .unwrap()
        .filter_map(|e| e.ok())
        .map(|e| e.path())
        .filter(|p| p.extension().map(|x| x == "dot").unwrap_or(false))
        .collect();
    files.sort();

    let modes = [("baseline", Mode::Baseline), ("occ-only", Mode::OccOnly), ("occ+bonus+fill", Mode::Full)];
    for (label, mode) in modes {
        let mut t = Tally::default();
        let mut examples: Vec<(String, String, String, String)> = Vec::new();
        for path in &files {
            let dot = std::fs::read_to_string(path).unwrap();
            let legend = parse_legend(&dot);
            for lab in each_record_label(&dot) {
                let Some(rec) = parse_record(&lab) else { continue };
                run_group(&rec.premises, &legend, mode, true, &mut t, &mut examples);
                run_group(&rec.conclusions, &legend, mode, true, &mut t, &mut examples);
            }
        }
        let pct = |a: u64, b: u64| if b == 0 { 0.0 } else { 100.0 * a as f64 / b as f64 };
        println!("==== MODE {label} ====");
        println!("ALL prem/concl cells : {}/{} = {:.3}%", t.all_ok, t.all, pct(t.all_ok, t.all));
        println!("wrapping cells       : {}/{} = {:.3}%", t.wrap_ok, t.wrap, pct(t.wrap_ok, t.wrap));
        println!("  multi-cell wrap    : {}/{} = {:.3}%", t.multi_wrap_ok, t.multi_wrap, pct(t.multi_wrap_ok, t.multi_wrap));
        println!("  abbr-group wrap    : {}/{} = {:.3}%", t.abbr_wrap_ok, t.abbr_wrap, pct(t.abbr_wrap_ok, t.abbr_wrap));
        println!(
            "residual: falseNeg {} (abbr {}) | falsePos {} | fillErr {} (abbr {})",
            t.false_neg, t.false_neg_abbr, t.false_pos, t.fill_err, t.fill_err_abbr
        );
        if mode == Mode::Full {
            // print one first-diverging-byte example per family
            for fam in ["falseNeg", "falsePos", "fillErr"] {
                if let Some((_, flat, want, got)) = examples.iter().find(|e| e.0 == fam) {
                    let fd = first_diverge(want, got);
                    println!("  [{fam}] first-diverge byte {fd}");
                    println!("      flat({}): {}", flat.chars().count(), flat);
                    println!("      want: {}", want);
                    println!("      got : {}", got);
                }
            }
        }
        println!();
    }
}

