// ---------- trigger-accuracy analysis (isolates the wrap DECISION from the
//            fill), comparing the crate's display-flat trigger against a
//            symmetric internal-width trigger computed on the un-abbreviated
//            widths for ALL cells (the round-11 candidate model). ----------

#[derive(Default)]
struct Trig {
    total: u64,
    disp_ok: u64, // crate display-flat trigger predicts \l-presence
    sym_ok: u64,  // symmetric internal-width trigger predicts \l-presence
    // split on abbreviated groups
    abbr_total: u64,
    abbr_disp_ok: u64,
    abbr_sym_ok: u64,
}

/// Symmetric internal-width trigger for a group: budget_i uses internal
/// occupancies for ALL cells, and the cell's OWN wrap is decided on its
/// internal flat (unlike group_widths_with, which uses the display flat).
fn sym_wraps(display: &[String], ua: &[String]) -> Vec<bool> {
    let n = display.len();
    let shapes: Vec<Shape> = ua.iter().map(|u| cell_shape(u)).collect();
    let cs: Vec<i64> = shapes.iter().map(|s| s.flat + s.tup_sur + s.uni_sur).collect();
    let ctot: i64 = cs.iter().sum();
    (0..n)
        .map(|i| {
            if n == 1 {
                shapes[i].flat > 87
            } else {
                let budget = (87 + shapes[i].bmax - (ctot - cs[i])).max(20);
                shapes[i].flat > budget
            }
        })
        .collect()
}

fn trigger_analysis(files: &[std::path::PathBuf]) {
    let mut t = Trig::default();
    for path in files {
        let dot = std::fs::read_to_string(path).unwrap();
        let legend = parse_legend(&dot);
        for lab in each_record_label(&dot) {
            let Some(rec) = parse_record(&lab) else { continue };
            for group in [&rec.premises, &rec.conclusions] {
                if group.is_empty() {
                    continue;
                }
                let display: Vec<String> = group.iter().map(|c| c.1.clone()).collect();
                let ua: Vec<String> = display.iter().map(|d| expand(d, &legend)).collect();
                let group_abbr = display.iter().zip(&ua).any(|(d, u)| d != u);
                let disp_budgets = group_widths_with(&display, &[]);
                let sym = sym_wraps(&display, &ua);
                for (k, (raw, disp)) in group.iter().enumerate() {
                    let actual = raw.contains("\\l");
                    let disp_pred =
                        wrap_cell_dot(disp, disp_budgets[k] as isize).contains("\\l");
                    t.total += 1;
                    if disp_pred == actual {
                        t.disp_ok += 1;
                    }
                    if sym[k] == actual {
                        t.sym_ok += 1;
                    }
                    if group_abbr {
                        t.abbr_total += 1;
                        if disp_pred == actual {
                            t.abbr_disp_ok += 1;
                        }
                        if sym[k] == actual {
                            t.abbr_sym_ok += 1;
                        }
                    }
                }
            }
        }
    }
    let pct = |a: u64, b: u64| if b == 0 { 0.0 } else { 100.0 * a as f64 / b as f64 };
    println!("==== TRIGGER ACCURACY (does \\l-presence match; fill ignored) ====");
    println!(
        "ALL prem/concl cells  display-trigger {}/{} = {:.3}%  |  symmetric-internal-trigger {}/{} = {:.3}%",
        t.disp_ok, t.total, pct(t.disp_ok, t.total),
        t.sym_ok, t.total, pct(t.sym_ok, t.total)
    );
    println!(
        "ABBREVIATED groups    display-trigger {}/{} = {:.3}%  |  symmetric-internal-trigger {}/{} = {:.3}%",
        t.abbr_disp_ok, t.abbr_total, pct(t.abbr_disp_ok, t.abbr_total),
        t.abbr_sym_ok, t.abbr_total, pct(t.abbr_sym_ok, t.abbr_total)
    );
    println!();
}

